import{_ as s,o as a,c as t,a7 as i}from"./chunks/framework.C4ZIv4ii.js";const k=JSON.parse('{"title":"Installing FalconCMS Pro","description":"","frontmatter":{},"headers":[],"relativePath":"guide/pro.md","filePath":"guide/pro.md","lastUpdated":1783791200000}'),o={name:"guide/pro.md"};function n(r,e,l,p,c,h){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="installing-falconcms-pro" tabindex="-1">Installing FalconCMS Pro <a class="header-anchor" href="#installing-falconcms-pro" aria-label="Permalink to &quot;Installing FalconCMS Pro&quot;">​</a></h1><p>FalconCMS is <strong>open-core</strong>. The free <code>falconcms/falconcms</code> package (MIT, on public Packagist) gives you the CMS, page builder, themes, menus, media and hooks API.</p><p><strong>Pro</strong> unlocks the commercial features:</p><ul><li><strong>E-commerce</strong> — storefront, cart, checkout, orders, coupons</li><li><strong>Multi-language</strong> — translated content and language switching</li><li><strong>Analytics</strong> — dashboard insights and reports</li><li><strong>Advanced page builder</strong> — the Pro elements, Library and Global Sections</li><li><strong>Custom fields</strong> — ACPT field groups</li><li><strong>Advanced login</strong> — multi-device &amp; magic login</li></ul><p>Pro ships as a separate, proprietary package — <code>falconcms/pro</code> — delivered from a <strong>private repository</strong>. It is never bundled in the free download, so you install it with Composer using the credentials you receive when you buy a license.</p><div class="tip custom-block"><p class="custom-block-title">You need two things</p><ol><li>A <strong>license key</strong> (<code>PRO-…</code> or <code>AGENCY-…</code>) — activates the features inside the dashboard.</li><li>A <strong>Composer token</strong> — lets Composer download the private <code>falconcms/pro</code> package.</li></ol><p>Both are emailed to you right after purchase (and are always available in your account portal). The license key is public-facing; <strong>keep the Composer token secret</strong> — treat it like a password.</p></div><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li>FalconCMS core <strong>v2.0</strong> or higher (<code>composer show falconcms/falconcms</code>)</li><li>PHP <strong>8.1+</strong></li><li>Composer <strong>2.x</strong></li></ul><p>If you are on core v1.x, <a href="/falconcms/guide/upgrade.html">upgrade to v2</a> first.</p><h2 id="step-1-—-add-the-private-repository" tabindex="-1">Step 1 — Add the private repository <a class="header-anchor" href="#step-1-—-add-the-private-repository" aria-label="Permalink to &quot;Step 1 — Add the private repository&quot;">​</a></h2><p>Tell Composer where the Pro package lives. Run this in your project root:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> repositories.falconcms-pro</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://repo.packagist.com/falconcms/</span></span></code></pre></div><p>This adds a <code>repositories</code> entry to your <code>composer.json</code>. You only do it once per project.</p><h2 id="step-2-—-authenticate-with-your-composer-token" tabindex="-1">Step 2 — Authenticate with your Composer token <a class="header-anchor" href="#step-2-—-authenticate-with-your-composer-token" aria-label="Permalink to &quot;Step 2 — Authenticate with your Composer token&quot;">​</a></h2><p>Store the token you received by email. This writes it to Composer&#39;s <strong>global</strong> auth file (<code>~/.composer/auth.json</code> or <code>COMPOSER_HOME/auth.json</code>), so it is <strong>not</strong> committed with your project:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http-basic.repo.packagist.com</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> YOUR-COMPOSER-TOKEN</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Never commit the token</p><p>Do not put the token in your project&#39;s <code>composer.json</code> or in version control. Use the global auth file (above), or an <code>auth.json</code> in the project root that is listed in <code>.gitignore</code>. For servers and CI, see <a href="#deploying-to-production">Deploying to production</a>.</p></div><h2 id="step-3-—-install-the-package" tabindex="-1">Step 3 — Install the package <a class="header-anchor" href="#step-3-—-install-the-package" aria-label="Permalink to &quot;Step 3 — Install the package&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> require</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> falconcms/pro</span></span></code></pre></div><p>Composer pulls <code>falconcms/pro</code> from the private repository and registers its service provider automatically (Laravel package discovery).</p><h2 id="step-4-—-activate-your-license-key" tabindex="-1">Step 4 — Activate your license key <a class="header-anchor" href="#step-4-—-activate-your-license-key" aria-label="Permalink to &quot;Step 4 — Activate your license key&quot;">​</a></h2><ol><li>Open your dashboard → <strong>Falcon Builder → License</strong>.</li><li>Paste your <strong>license key</strong> (<code>PRO-…</code> or <code>AGENCY-…</code>) and click <strong>Activate</strong>.</li><li>The status card turns green and every Pro feature unlocks.</li></ol><p>That&#39;s it. The key is validated against your plan and stored privately on your site.</p><h2 id="updating-pro" tabindex="-1">Updating Pro <a class="header-anchor" href="#updating-pro" aria-label="Permalink to &quot;Updating Pro&quot;">​</a></h2><p>When a new Pro version is released, update it exactly like the core package:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> falconcms/pro</span></span></code></pre></div><p>Or update both together:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> falconcms/falconcms</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> falconcms/pro</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Keep core and Pro in step</p><p>Pro requires a matching core major version. When you move to a new core major (e.g. v2 → v3), update both at once so their constraints resolve.</p></div><h2 id="deploying-to-production" tabindex="-1">Deploying to production <a class="header-anchor" href="#deploying-to-production" aria-label="Permalink to &quot;Deploying to production&quot;">​</a></h2><p>Your production server and CI pipeline also need the Composer token to install Pro. Pick whichever fits your setup — <strong>do not</strong> hard-code the token in tracked files.</p><p><strong>Option A — <code>auth.json</code> on the server</strong> (git-ignored):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;http-basic&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;repo.packagist.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;username&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;password&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;YOUR-COMPOSER-TOKEN&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Option B — environment variable</strong> (great for CI / Docker):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> COMPOSER_AUTH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;{&quot;http-basic&quot;:{&quot;repo.packagist.com&quot;:{&quot;username&quot;:&quot;token&quot;,&quot;password&quot;:&quot;YOUR-COMPOSER-TOKEN&quot;}}}&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-dev</span></span></code></pre></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p><strong>“Key saved, but Pro is not active.”</strong> The license key is stored but the <code>falconcms/pro</code> package isn&#39;t installed on this site yet. Run Steps 1–3 above, then reload the License page.</p><p><strong>Composer: <code>Could not authenticate against repo.packagist.com</code></strong> The token is missing or wrong. Re-run Step 2, or check your <code>auth.json</code>. Confirm the token in your account portal hasn&#39;t been revoked.</p><p><strong>Composer: <code>Could not find package falconcms/pro</code></strong> The private repository entry is missing. Re-run Step 1, then <code>composer require falconcms/pro</code>.</p><p><strong>A key <code>did not resolve to a valid plan.</code></strong> Double-check the key was copied in full. If it still fails, deactivate and re-activate, or contact support with your order reference.</p><div class="tip custom-block"><p class="custom-block-title">Lost your key or token?</p><p>Both are always available in your account portal, and a leaked Composer token can be revoked and reissued there without affecting your license key.</p></div>`,41)])])}const g=s(o,[["render",n]]);export{k as __pageData,g as default};
